#include <bits/stdc++.h>
using namespace std;
struct a{
    char l,r,s;
}t[1000001];
void q(long long x){
    cout<<t[x].s;
    if(t[x].l!=0){
        q(t[x].l);
    }
    if(t[x].r!=0){
        q(t[x].r);
    }
}
int main(){
    long long n;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>t[i].s>>t[i].l>>t[i].r;
        	if(t[i].l!='*')
			{
				t[t[i].l-'a'+1].s=t[i].l;
				t[t[i].s-'a'+1].l=t[i].l-'a'+1;
			}
			if(t[i].r!='*')
			{
				t[t[i].r-'a'+1].s=t[i].r;
				t[t[i].s-'a'+1].r=t[i].r-'a'+1;
			}
    }
    q(1);
    return 0;
}
